mapper.select:
SELECT 
FROM vso_notify_task t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.notify_task_id = #{notifyTaskId}


    AND t.order_id = #{orderId}


    AND t.notify_type = #{notifyType}


    AND t.receiver_type = #{receiverType}


    AND t.receiver_id = #{receiverId}


    AND t.send_status = #{sendStatus}

ORDER BY t.id DESC

SELECT 
FROM vso_notify_task t
WHERE t.row_valid = 1

    AND t.order_id = #{params.orderId}


    AND t.notify_type = #{params.notifyType}


    AND t.receiver_type = #{params.receiverType}


    AND t.send_status = #{params.sendStatus}

ORDER BY t.id DESC

